@app.route('/dashboard')
def dashboard():
    pets = load_pets()
    # Featured pets: last 5 available by date_added descending
    available_pets = [p for p in pets if p['status'] == 'Available']
    try:
        available_pets.sort(key=lambda pet: datetime.strptime(pet['date_added'], '%Y-%m-%d'), reverse=True)
    except Exception:
        pass
    featured_pets = available_pets[:5]

    # Add photo_url as empty string (schema doesn't have photo_url)
    for pet in featured_pets:
        pet['photo_url'] = ''

    # Recent activities: combine pet additions and latest application statuses
    activities = []
    applications = load_applications()
    for pet in pets:
        activities.append((pet['date_added'], f"New pet added: {pet['name']}"))
    for app in applications:
        activities.append((app['date_submitted'], f"Application by {app['applicant_name']} is {app['status']}"))
    try:
        activities.sort(key=lambda x: datetime.strptime(x[0], '%Y-%m-%d'), reverse=True)
    except Exception:
        pass
    recent_activities = [desc for _, desc in activities[:5]]

    return render_template('dashboard.html', featured_pets=featured_pets, recent_activities=recent_activities)

