@app.route('/messages', methods=['GET', 'POST'])
def messages():
    username = get_current_username()
    messages = load_messages()

    conversations = {}

    if request.method == 'POST':
        form = request.form
        recipient = form.get('recipient_username', '').strip()
        subject = form.get('subject', '').strip()
        content = form.get('content', '').strip()

        if not recipient or not subject or not content:
            submission_result = 'Error: Missing recipient, subject, or content.'
        else:
            message_id = max((m['message_id'] for m in messages), default=0) + 1
            timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            new_message = {
                'message_id': message_id,
                'sender_username': username,
                'recipient_username': recipient,
                'subject': subject,
                'content': content,
                'timestamp': timestamp,
                'is_read': False
            }
            messages.append(new_message)
            save_messages(messages)
            submission_result = 'Success: Message sent.'

        conversations = build_conversations(messages, username)

        return render_template('messages.html', conversations=conversations, submission_result=submission_result)

    # GET
    conversations = build_conversations(messages, username)
    return render_template('messages.html', conversations=conversations, submission_result='')


def build_conversations(messages, username):
    conv = {}
    for msg in messages:
        if msg['sender_username'] == username or msg['recipient_username'] == username:
            other = msg['recipient_username'] if msg['sender_username'] == username else msg['sender_username']
            if other not in conv:
                conv[other] = {
                    'recipient_username': other,
                    'last_message': msg['content'],
                    'unread_count': 0,
                    'last_timestamp': msg['timestamp']
                }
            else:
                if datetime.strptime(msg['timestamp'], '%Y-%m-%d %H:%M:%S') > datetime.strptime(conv[other]['last_timestamp'], '%Y-%m-%d %H:%M:%S'):
                    conv[other]['last_message'] = msg['content']
                    conv[other]['last_timestamp'] = msg['timestamp']
            if not msg['is_read'] and msg['recipient_username'] == username:
                conv[other]['unread_count'] += 1
    res = []
    for c in conv.values():
        c.pop('last_timestamp', None)
        res.append(c)
    return res

@app.route('/profile', methods=['GET', 'POST'])
