from flask import Flask, render_template, request, redirect, url_for, abort, flash
import os

app = Flask(__name__)
app.secret_key = 'secret-key-for-session'

data_dir = 'data'

# Data loading functions

def load_auctions():
    auctions = {}
    try:
        with open(os.path.join(data_dir, 'auctions.txt'), 'r', encoding='utf-8') as f:
            lines = f.readlines()
            for line in lines:
                parts = line.strip().split('|')
                if len(parts) < 7:
                    continue
                id_ = parts[0]
                auctions[id_] = {
                    'id': id_,
                    'title': parts[1],
                    'starting_price': float(parts[2]),
                    'category_id': parts[3],
                    'status': parts[4],
                    'seller': parts[5],
                    'description': parts[6],
                    'bids': []
                }
    except Exception:
        pass
    return auctions


def load_categories():
    categories = {}
    try:
        with open(os.path.join(data_dir, 'categories.txt'), 'r', encoding='utf-8') as f:
            lines = f.readlines()
            for line in lines:
                parts = line.strip().split('|')
                if len(parts) < 2:
                    continue
                categories[parts[0]] = parts[1]
    except Exception:
        pass
    return categories


def load_bids():
    bids = []
    try:
        with open(os.path.join(data_dir, 'bids.txt'), 'r', encoding='utf-8') as f:
            lines = f.readlines()
            for line in lines:
                parts = line.strip().split('|')
                if len(parts) < 4:
                    continue
                bid = {
                    'id': parts[0],
                    'auction_id': parts[1],
                    'bidder': parts[2],
