# Helper functions

def get_company_by_id(company_id):
    for c in load_companies():
        if c['company_id'] == company_id:
            return c
    return None


def get_job_by_id(job_id):
    for j in load_jobs():
        if j['job_id'] == job_id:
            return j
    return None


def get_category_name_by_id(category_id):
    for cat in load_categories():
        if cat['category_id'] == category_id:
            return cat['category_name']
    return None


def get_resume_by_id(resume_id):
    for r in load_resumes():
        if r['resume_id'] == resume_id:
            return r
    return None


def get_applications_filtered(status_filter=None):
    applications = load_applications()
    if status_filter and status_filter.strip():
        filtered = [a for a in applications if a['status'].lower() == status_filter.lower()]
    else:
        filtered = applications
    return filtered


def filter_jobs(jobs, category_name=None, location=None, search_query=None):
    results = jobs
    if category_name:
        results = [j for j in results if j['category'] == category_name]
    if location:
        results = [j for j in results if j['location'].lower() == location.lower()]
    if search_query:
        lowerq = search_query.lower()
        results = [j for j in results if lowerq in j['title'].lower() or lowerq in get_company_by_id(j['company_id'])['company_name'].lower() or lowerq in j['location'].lower()]
    return results


def filter_companies(companies, search_query=None):
    if not search_query:
        return companies
    lowerq = search_query.lower()
    filtered = [c for c in companies if lowerq in c['company_name'].lower() or lowerq in c['industry'].lower()]
    return filtered


def next_id(items, key_name):
    if not items:
        return 1
    return max(i[key_name] for i in items) + 1


def format_salary_range(smin, smax):
    return f"${smin:,} - ${smax:,}"


# Routes

@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard_page'))


@app.route('/dashboard')
def dashboard_page():
    jobs = load_jobs()
    companies = load_companies()

    # Featured jobs: top 5 jobs ordered by posted_date descending (most recent)
    jobs_sorted = sorted(jobs, key=lambda x: x['posted_date'], reverse=True)
    featured_jobs = []
    for job in jobs_sorted[:5]:
        comp = get_company_by_id(job['company_id'])
        if comp is None:
            continue
        featured_jobs.append({
            'job_id': job['job_id'],
            'title': job['title'],
            'company_name': comp['company_name'],
            'location': job['location'],
            'salary_range': format_salary_range(job['salary_min'], job['salary_max'])
        })

    # Latest jobs similar to featured jobs but could be for distinct context - use 5 most recent
    latest_jobs = featured_jobs[:5]

    categories = [c['category_name'] for c in load_categories()]
    locations = sorted(set(j['location'] for j in jobs))

    return render_template('dashboard.html', featured_jobs=featured_jobs, latest_jobs=latest_jobs, categories=categories, locations=locations)


@app.route('/jobs')
def job_listings_page():
    # Filters
    category = request.args.get('category')
    location = request.args.get('location')
    search_query = request.args.get('q')

    jobs = load_jobs()
    filtered_jobs = filter_jobs(jobs, category, location, search_query)

    # Prepare jobs list for context with required fields
    jobs_context = []
    for j in filtered_jobs:
        comp = get_company_by_id(j['company_id'])
        if comp is None:
            continue
        jobs_context.append({
            'job_id': j['job_id'],
            'title': j['title'],
            'company_name': comp['company_name'],
            'location': j['location'],
            'salary_min': j['salary_min'],
            'salary_max': j['salary_max'],
            'category': j['category']
        })

    categories = [c['category_name'] for c in load_categories()]
    locations = sorted(set(j['location'] for j in load_jobs()))

    return render_template('job_listings.html', jobs=jobs_context, categories=categories, locations=locations, selected_category=category, selected_location=location, search_query=search_query)


