    except Exception:
        pass


# Utility to get next ID

def next_id(items, key):
    if not items:
        return 1
    return max(item[key] for item in items) + 1


# Lookup helpers

def get_company_by_id(company_id):
    companies = load_companies()
    for c in companies:
        if c['company_id'] == company_id:
            return c
    return None


def get_job_by_id(job_id):
    jobs = load_jobs()
    for j in jobs:
        if j['job_id'] == job_id:
            return j
    return None


def get_resume_by_id(resume_id):
    resumes = load_resumes()
    for r in resumes:
        if r['resume_id'] == resume_id:
            return r
    return None


# Filters

def filter_jobs(jobs, category=None, location=None, search_query=None):
    filtered = jobs
    if category:
        filtered = [j for j in filtered if j['category'] == category]
    if location:
        filtered = [j for j in filtered if j['location'].lower() == location.lower()]
    if search_query:
        q = search_query.lower()
        def job_match(j):
            comp = get_company_by_id(j['company_id'])
            if not comp:
                return False
            return (q in j['title'].lower() or q in comp['company_name'].lower() or q in j['location'].lower())
        filtered = [j for j in filtered if job_match(j)]
    return filtered


def filter_companies(companies, search_query=None):
    if not search_query:
        return companies
    q = search_query.lower()
    filtered = [c for c in companies if (q in c['company_name'].lower() or q in c['industry'].lower())]
    return filtered


