from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import date

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper functions to load and save data from/to files

def load_properties():
    properties = []
    try:
        with open('data/properties.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 11:
                    continue
                property_id = int(parts[0])
                address = parts[1]
                location = parts[2]
                try:
                    price = float(parts[3])
                except ValueError:
                    price = 0.0
                property_type = parts[4]
                bedrooms = int(parts[5])
                try:
                    bathrooms = float(parts[6])
                except ValueError:
                    bathrooms = 0.0
                square_feet = int(parts[7])
                description = parts[8]
                agent_id = int(parts[9])
                status = parts[10]
                prop = {
                    'property_id': property_id,
                    'address': address,
                    'location': location,
                    'price': price,
                    'property_type': property_type,
                    'bedrooms': bedrooms,
                    'bathrooms': bathrooms,
                    'square_feet': square_feet,
                    'description': description,
                    'agent_id': agent_id,
                    'status': status
                }
                properties.append(prop)
    except FileNotFoundError:
        pass
    return properties


def load_locations():
    locations = []
    try:
        with open('data/locations.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                location_id = int(parts[0])
                location_name = parts[1]
                region = parts[2]
                try:
                    average_price = float(parts[3])
                except ValueError:
                    average_price = 0.0
                try:
                    property_count = int(parts[4])
                except ValueError:
                    property_count = 0
                description = parts[5]
                location = {
                    'location_id': location_id,
                    'location_name': location_name,
                    'region': region,
                    'average_price': average_price,
                    'property_count': property_count,
                    'description': description
                }
                locations.append(location)
    except FileNotFoundError:
        pass
    return locations


def load_inquiries():
    inquiries = []
    try:
        with open('data/inquiries.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 8:
                    continue
                inquiry_id = int(parts[0])
                property_id = int(parts[1])
                customer_name = parts[2]
                customer_email = parts[3]
                customer_phone = parts[4]
                message = parts[5]
                inquiry_date = parts[6]
                status = parts[7]
                inquiry = {
                    'inquiry_id': inquiry_id,
                    'property_id': property_id,
                    'customer_name': customer_name,
                    'customer_email': customer_email,
                    'customer_phone': customer_phone,
                    'message': message,
                    'inquiry_date': inquiry_date,
                    'status': status
                }
                inquiries.append(inquiry)
    except FileNotFoundError:
        pass
    return inquiries


def save_inquiries(inquiries):
    try:
        with open('data/inquiries.txt', 'w', encoding='utf-8') as f:
            for inquiry in inquiries:
                line = '|'.join([
                    str(inquiry['inquiry_id']),
                    str(inquiry['property_id']),
                    inquiry['customer_name'],
                    inquiry['customer_email'],
                    inquiry['customer_phone'],
                    inquiry['message'],
                    inquiry['inquiry_date'],
                    inquiry['status']
                ])
                f.write(line + '\n')
    except IOError:
        pass


def load_favorites():
    favorites = []
    try:
        with open('data/favorites.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 3:
                    continue
                favorite_id = int(parts[0])
                property_id = int(parts[1])
                added_date = parts[2]
                fav = {
                    'favorite_id': favorite_id,
                    'property_id': property_id,
                    'added_date': added_date
                }
                favorites.append(fav)
    except FileNotFoundError:
        pass
    return favorites


def save_favorites(favorites):
    try:
        with open('data/favorites.txt', 'w', encoding='utf-8') as f:
            for fav in favorites:
                line = '|'.join([
                    str(fav['favorite_id']),
                    str(fav['property_id']),
                    fav['added_date']
                ])
                f.write(line + '\n')
    except IOError:
        pass


def load_agents():
    agents = []
    try:
        with open('data/agents.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                agent_id = int(parts[0])
                agent_name = parts[1]
                specialization = parts[2]
                email = parts[3]
                phone = parts[4]
                try:
                    properties_sold = int(parts[5])
                except ValueError:
                    properties_sold = 0
                agent = {
                    'agent_id': agent_id,
                    'agent_name': agent_name,
                    'specialization': specialization,
                    'email': email,
                    'phone': phone,
                    'properties_sold': properties_sold
                }
                agents.append(agent)
    except FileNotFoundError:
        pass
    return agents


