# Root Route: redirects to /dashboard
@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard_page'))


# 1. Dashboard Page
@app.route('/dashboard')
def dashboard_page():
    properties = load_properties()
    # Filter featured properties - Assume those with status 'Available' and lowest property_id among first 3 (or just first 3 available)
    featured_properties = [p for p in properties if p['status'] == 'Available'][:3]
    # Recent listings - most recent by descending property_id (simulate recency by property_id order), limit 5
    properties_sorted = sorted(
        [p for p in properties if p['status'] == 'Available'],
        key=lambda x: x['property_id'],
        reverse=True
    )
    recent_listings = properties_sorted[:5]
    # For featured_properties and recent_listings, keys required: property_id, address, price, bedrooms, bathrooms
    featured_properties_context = [{
        'property_id': p['property_id'],
        'address': p['address'],
        'price': p['price'],
        'bedrooms': p['bedrooms'],
        'bathrooms': p['bathrooms']
    } for p in featured_properties]
    recent_listings_context = [{
        'property_id': p['property_id'],
        'address': p['address'],
        'price': p['price'],
        'bedrooms': p['bedrooms'],
        'bathrooms': p['bathrooms']
    } for p in recent_listings]
    return render_template('dashboard.html', featured_properties=featured_properties_context, recent_listings=recent_listings_context)


