    else:
        filtered_inquiries = [inq for inq in inquiries if inq['status'] == status_filter]

    # Build context inquiries with keys: inquiry_id, property_id, property_address, inquiry_date, status, customer_name, customer_email, customer_phone
    inquiries_context = [{
        'inquiry_id': inq['inquiry_id'],
        'property_id': inq['property_id'],
        'property_address': property_address_lookup.get(inq['property_id'], 'Unknown'),
        'inquiry_date': inq['inquiry_date'],
        'status': inq['status'],
        'customer_name': inq['customer_name'],
        'customer_email': inq['customer_email'],
        'customer_phone': inq['customer_phone']
    } for inq in filtered_inquiries]

    return render_template('my_inquiries.html', inquiries=inquiries_context, status_filter=status_filter)


