@app.route('/inquiry', methods=['POST'])
def submit_inquiry():
    form = request.form
    try:
        property_id = int(form.get('property_id', '').strip())
    except Exception:
        property_id = None
    inquiry_name = form.get('inquiry_name', '').strip()
    inquiry_email = form.get('inquiry_email', '').strip()
    inquiry_phone = form.get('inquiry_phone', '').strip()
    inquiry_message = form.get('inquiry_message', '').strip()

    # Validate input: property_id must be valid and exist, name, email, phone and message nonempty
    properties = load_properties()
    property_valid = any(p['property_id'] == property_id and p['status'] == 'Available' for p in properties) if property_id else False

    input_valid = (property_valid and inquiry_name != '' and inquiry_email != '' and inquiry_phone != '' and inquiry_message != '')

    if not input_valid:
        # Re-render with properties and possibly error message (not specified to show errors), re-render inquiry.html
        available_properties = [p for p in properties if p['status'] == 'Available']
        properties_context = [{
            'property_id': p['property_id'],
            'address': p['address']
        } for p in available_properties]
        return render_template('inquiry.html', properties=properties_context)

    # Load existing inquiries to get max inquiry_id
    inquiries = load_inquiries()
    max_inquiry_id = max((inq['inquiry_id'] for inq in inquiries), default=0)
    new_inquiry_id = max_inquiry_id + 1

    today_iso = date.today().isoformat()
    new_inquiry = {
        'inquiry_id': new_inquiry_id,
        'property_id': property_id,
        'customer_name': inquiry_name,
        'customer_email': inquiry_email,
        'customer_phone': inquiry_phone,
        'message': inquiry_message,
        'inquiry_date': today_iso,
        'status': 'Pending'
    }
    inquiries.append(new_inquiry)
    save_inquiries(inquiries)

    # Redirect to /my-inquiries on success
    return redirect(url_for('my_inquiries_page'))


