@app.route('/inquiry', methods=['POST'])
def submit_inquiry():
    form = request.form
    property_id = form.get('property_id')
    inquiry_name = form.get('inquiry_name', '').strip()
    inquiry_email = form.get('inquiry_email', '').strip()
    inquiry_phone = form.get('inquiry_phone', '').strip()
    inquiry_message = form.get('inquiry_message', '').strip()

    try:
        property_id = int(property_id)
    except (ValueError, TypeError):
        property_id = None

    properties = load_properties()
    valid_property = any(p['property_id'] == property_id and p['status'] == 'Available' for p in properties)

    if not (property_id and valid_property and inquiry_name and inquiry_email and inquiry_phone and inquiry_message):
        # re-render inquiry page with properties on failure
        available_properties = [p for p in properties if p['status'] == 'Available']
        properties_context = [{
            'property_id': p['property_id'],
            'address': p['address']
        } for p in available_properties]
        return render_template('inquiry.html', properties=properties_context)

    inquiries = load_inquiries()
    max_id = max([inq['inquiry_id'] for inq in inquiries], default=0)
    new_id = max_id + 1
    today = date.today().isoformat()
    new_inquiry = {
        'inquiry_id': new_id,
        'property_id': property_id,
        'customer_name': inquiry_name,
        'customer_email': inquiry_email,
        'customer_phone': inquiry_phone,
        'message': inquiry_message,
        'inquiry_date': today,
        'status': 'Pending'
    }
    inquiries.append(new_inquiry)
    save_inquiries(inquiries)
    return redirect(url_for('my_inquiries_page'))


