# Data loading and saving utility functions

def load_properties():
    props = []
    try:
        with open('data/properties.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 11:
                    continue
                try:
                    prop = {
                        'property_id': int(parts[0]),
                        'address': parts[1],
                        'location': parts[2],
                        'price': float(parts[3]),
                        'property_type': parts[4],
                        'bedrooms': int(parts[5]),
                        'bathrooms': float(parts[6]),
                        'square_feet': int(parts[7]),
                        'description': parts[8],
                        'agent_id': int(parts[9]),
                        'status': parts[10]
                    }
                    props.append(prop)
                except Exception:
                    continue
    except FileNotFoundError:
        pass
    return props


def load_locations():
    locs = []
    try:
        with open('data/locations.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 6:
                    continue
                try:
                    loc = {
                        'location_id': int(parts[0]),
                        'location_name': parts[1],
                        'region': parts[2],
                        'average_price': float(parts[3]),
                        'property_count': int(parts[4]),
                        'description': parts[5]
                    }
                    locs.append(loc)
                except Exception:
                    continue
    except FileNotFoundError:
        pass
    return locs


def load_inquiries():
    inqs = []
    try:
        with open('data/inquiries.txt', 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) != 8:
                    continue
                try:
                    inq = {
                        'inquiry_id': int(parts[0]),
                        'property_id': int(parts[1]),
                        'customer_name': parts[2],
                        'customer_email': parts[3],
                        'customer_phone': parts[4],
                        'message': parts[5],
                        'inquiry_date': parts[6],
                        'status': parts[7]
                    }
                    inqs.append(inq)
                except Exception:
                    continue
    except FileNotFoundError:
        pass
    return inqs


def save_inquiries(inquiries):
    try:
        with open('data/inquiries.txt', 'w', encoding='utf-8') as f:
            for inq in inquiries:
                line = '|'.join([
                    str(inq['inquiry_id']),
                    str(inq['property_id']),
                    inq['customer_name'],
                    inq['customer_email'],
                    inq['customer_phone'],
                    inq['message'],
                    inq['inquiry_date'],
                    inq['status']
                ])
                f.write(line + '\n')
    except IOError:
        pass


def load_favorites():
    favs = []
