def load_destinations():
    filepath = 'data/destinations.txt'
    destinations = []
    if not os.path.exists(filepath):
        return destinations
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 7:
                    continue
                dest_id = int(parts[0])
                name = parts[1]
                country = parts[2]
                region = parts[3]
                description = parts[4]
                attractions = [a.strip() for a in parts[5].split(',')] if parts[5].strip() else []
                climate = parts[6]
                destinations.append({
                    'dest_id': dest_id,
                    'name': name,
                    'country': country,
                    'region': region,
                    'description': description,
                    'attractions': attractions,
                    'climate': climate
                })
    except Exception:
        # on any file I/O error, return empty list
        return []
    return destinations

