from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Data loading functions

def load_destinations():
    filepath = 'data/destinations.txt'
    destinations = []
    if not os.path.exists(filepath):
        return destinations
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 7:
                    continue
                dest_id = int(parts[0])
                name = parts[1]
                country = parts[2]
                region = parts[3]
                description = parts[4]
                attractions = [x.strip() for x in parts[5].split(',')] if parts[5].strip() else []
                climate = parts[6]
                destinations.append({
                    'dest_id': dest_id,
                    'name': name,
                    'country': country,
                    'region': region,
                    'description': description,
                    'attractions': attractions,
                    'climate': climate
                })
    except Exception:
        return []
    return destinations

def load_featured_destinations():
    all_dest = load_destinations()
    featured = []
    for d in all_dest[:3]:
        featured.append({
            'dest_id': d['dest_id'],
            'name': d['name'],
            'country': d['country'],
            'image_url': f"/static/images/destinations/{d['dest_id']}.jpg"
        })
    return featured

