from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions to load data

def load_memberships():
    filename = os.path.join(DATA_DIR, 'memberships.txt')
    memberships = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    membership_id = int(parts[0])
                    plan_name = parts[1]
                    price = float(parts[2])
                    billing_cycle = parts[3]
                    features = parts[4].split(', ')
                    max_classes = parts[5]
                    if max_classes.isdigit():
                        max_classes = int(max_classes)
                    memberships.append({
                        'membership_id': membership_id,
                        'plan_name': plan_name,
                        'price': price,
                        'billing_cycle': billing_cycle,
                        'features': features,
                        'max_classes': max_classes
                    })
    except FileNotFoundError:
        pass
    return memberships


def load_classes():
    filename = os.path.join(DATA_DIR, 'classes.txt')
    classes = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    class_id = int(parts[0])
                    class_name = parts[1]
                    trainer_id = int(parts[2])
                    class_type = parts[3]
                    schedule_day = parts[4]
                    schedule_time = parts[5]
                    capacity = int(parts[6])
                    duration = int(parts[7])
                    classes.append({
                        'class_id': class_id,
                        'class_name': class_name,
                        'trainer_id': trainer_id,
                        'class_type': class_type,
                        'schedule_day': schedule_day,
                        'schedule_time': schedule_time,
                        'capacity': capacity,
                        'duration': duration
                    })
    except FileNotFoundError:
        pass
    return classes


def load_trainers():
    filename = os.path.join(DATA_DIR, 'trainers.txt')
    trainers = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    trainer_id = int(parts[0])
                    name = parts[1]
                    specialty = parts[2]
                    certifications = parts[3].split(', ')
                    experience_years = int(parts[4])
                    bio = parts[5]
                    trainers.append({
                        'trainer_id': trainer_id,
                        'name': name,
                        'specialty': specialty,
                        'certifications': certifications,
                        'experience_years': experience_years,
                        'bio': bio
                    })
    except FileNotFoundError:
        pass
    return trainers


def load_bookings():
    filename = os.path.join(DATA_DIR, 'bookings.txt')
    bookings = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 7:
                    booking_id = int(parts[0])
                    member_name = parts[1]
                    trainer_id = int(parts[2])
                    booking_date = parts[3]
                    booking_time = parts[4]
                    duration_minutes = int(parts[5])
                    status = parts[6]
                    bookings.append({
                        'booking_id': booking_id,
                        'member_name': member_name,
                        'trainer_id': trainer_id,
                        'booking_date': booking_date,
                        'booking_time': booking_time,
                        'duration_minutes': duration_minutes,
                        'status': status
                    })
    except FileNotFoundError:
        pass
    return bookings


def save_booking(booking):
    filename = os.path.join(DATA_DIR, 'bookings.txt')
    # Find the max booking_id to assign new id
    bookings = load_bookings()
    max_id = max([b['booking_id'] for b in bookings], default=0)
    new_id = max_id + 1
    try:
        with open(filename, 'a', encoding='utf-8') as f:
            line = f"{new_id}|{booking['member_name']}|{booking['trainer_id']}|{booking['booking_date']}|{booking['booking_time']}|{booking['duration_minutes']}|{booking['status']}\n"
            f.write(line)
            return new_id
    except Exception:
        return None


def load_workouts():
    filename = os.path.join(DATA_DIR, 'workouts.txt')
    workouts = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 7:
                    workout_id = int(parts[0])
                    member_name = parts[1]
                    workout_type = parts[2]
                    workout_date = parts[3]
                    duration_minutes = int(parts[4])
                    calories_burned = int(parts[5])
                    notes = parts[6]
                    workouts.append({
                        'workout_id': workout_id,
                        'member_name': member_name,
                        'workout_type': workout_type,
                        'workout_date': workout_date,
                        'duration_minutes': duration_minutes,
                        'calories_burned': calories_burned,
                        'notes': notes
                    })
    except FileNotFoundError:
        pass
    return workouts


def save_workout(workout):
    filename = os.path.join(DATA_DIR, 'workouts.txt')
    workouts = load_workouts()
    max_id = max([w['workout_id'] for w in workouts], default=0)
    new_id = max_id + 1
    try:
        with open(filename, 'a', encoding='utf-8') as f:
            line = f"{new_id}|{workout['member_name']}|{workout['workout_type']}|{workout['workout_date']}|{workout['duration_minutes']}|{workout['calories_burned']}|{workout['notes']}\n"
            f.write(line)
            return new_id
    except Exception:
        return None

