    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            lines = f.read().splitlines()
            if lines:
                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        movie = dict(zip(header, fields))
                        # Convert rating and duration
                        try:
                            movie['rating'] = float(movie['rating']) if movie['rating'] else None
                        except:
                            movie['rating'] = None
                        try:
                            movie['duration'] = int(movie['duration']) if movie['duration'] else None
                        except:
                            movie['duration'] = None
                        movies.append(movie)
    except IOError:
        pass
    return movies


def load_theaters():
    theaters = []
