                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        theater = dict(zip(header, fields))
                        try:
                            theater['screens'] = int(theater['screens']) if theater['screens'] else None
