    filepath = 'data/showtimes.txt'
    if not os.path.exists(filepath):
        return showtimes
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            lines = f.read().splitlines()
            if lines:
                header = lines[0].split('|')
                for line in lines[1:]:
                    fields = line.split('|')
                    if len(fields) == len(header):
                        showtime = dict(zip(header, fields))
                        try:
                            showtime['showtime_id'] = int(showtime['showtime_id'])
                            showtime['movie_id'] = int(showtime['movie_id'])
                            showtime['theater_id'] = int(showtime['theater_id'])
                            showtime['price'] = float(showtime['price'])
                            showtime['available_seats'] = int(showtime['available_seats'])
                        except:
                            pass
                        showtimes.append(showtime)
    except IOError:
        pass
    return showtimes


