@app.route('/showtimes/<int:movie_id>', methods=['GET', 'POST'])
def showtime_selection(movie_id):
    movies = load_movies()
    movie = next((m for m in movies if int(m.get('movie_id')) == movie_id), None)
    if movie is None:
        return "Movie not found", 404

    showtimes = load_showtimes()
    theaters = load_theaters()

    # Filter showtimes for movie
    filtered_showtimes = [s for s in showtimes if s['movie_id'] == movie_id]

    # Apply theater filter and date filter
    theaters_dict = {t['theater_id']: t for t in theaters}

    theater_filter = None
    date_filter = None
    if request.method == 'POST':
        theater_filter = request.form.get('theater_filter')
        date_filter = request.form.get('date_filter')
        if theater_filter:
            try:
                theater_filter = int(theater_filter)
            except:
                theater_filter = None

    showtimes_filtered = []
    for st in filtered_showtimes:
        # Filter by theater
        if theater_filter and st['theater_id'] != theater_filter:
            continue
        # Filter by date
        if date_filter and st['showtime_date'] != date_filter:
            continue
        st_copy = st.copy()
        theater = theaters_dict.get(st['theater_id'])
        if theater:
            st_copy['theater_name'] = theater['theater_name']
        else:
            st_copy['theater_name'] = 'Unknown'
        showtimes_filtered.append(st_copy)

    return render_template('showtime_selection.html', movie=movie, showtimes=showtimes_filtered, selected_theater_id=theater_filter, selected_date=date_filter)


