    showtime = next((s for s in showtimes if s['showtime_id'] == showtime_id), None)
    if showtime is None:
        return "Showtime not found", 404

    movies = load_movies()
    movie = next((m for m in movies if int(m['movie_id']) == showtime['movie_id']), None)
    if movie is None:
        return "Movie not found", 404

    seats = load_seats()

    # Filter seats by theater_id
    theater_id = showtime['theater_id']
    seats_for_showtime = [seat for seat in seats if seat['theater_id'] == theater_id]

    # Organize seats by row
    seat_map = {}
    for seat in seats_for_showtime:
        row = seat['row']
        seat_map.setdefault(row, []).append(seat)

    # Sort seats by column
    for row in seat_map:
        seat_map[row].sort(key=lambda s: s['column'])

    return render_template('seat_selection.html',
                           seat_map=seat_map,
                           movie_title=movie['title'],
                           showtime_date=showtime['showtime_date'],
                           showtime_time=showtime['showtime_time'],
                           showtime_id=showtime_id)


@app.route('/booking-confirmation/<int:showtime_id>', methods=['GET', 'POST'])
def booking_confirmation(showtime_id):
    showtimes = load_showtimes()
    showtime = next((s for s in showtimes if s['showtime_id'] == showtime_id), None)
    if showtime is None:
        return "Showtime not found", 404

    movies = load_movies()
    movie = next((m for m in movies if int(m['movie_id']) == showtime['movie_id']), None)

    theaters = load_theaters()
    theater = next((t for t in theaters if t['theater_id'] == showtime['theater_id']), None)

    if request.method == 'POST':
        customer_name = request.form.get('customer_name')
        selected_seats = request.form.getlist('selected_seats')

        if not customer_name or not selected_seats:
            error = "Please enter your name and select at least one seat."
            return render_template('booking_confirmation.html', 
                                   showtime_info=showtime,
                                   movie_title=movie.get('title') if movie else 'Unknown',
                                   theater_name=theater.get('theater_name') if theater else 'Unknown',
                                   selected_seats=selected_seats,
                                   customer_name=customer_name,
                                   error=error)

        # Calculate total price
        total_price = len(selected_seats) * showtime.get('price', 0)

        # Save booking to bookings.txt file
        try:
            filepath = 'data/bookings.txt'
            bookings = load_bookings()
            if bookings:
                next_booking_id = max(b['booking_id'] for b in bookings) + 1
            else:
                next_booking_id = 1

            seats_str = ','.join(selected_seats)
            booking_date = date.today().isoformat()

            booking_line = f"{next_booking_id}|{showtime_id}|{customer_name}|customer@example.com|{booking_date}|{total_price:.2f}|Confirmed|{seats_str}\n"

            with open(filepath, 'a', encoding='utf-8') as file:
                file.write(booking_line)
        except IOError:
            error = "Failed to save booking. Please try again."
            return render_template('booking_confirmation.html', 
                                   showtime_info=showtime,
                                   movie_title=movie.get('title') if movie else 'Unknown',
                                   theater_name=theater.get('theater_name') if theater else 'Unknown',
                                   selected_seats=selected_seats,
                                   customer_name=customer_name,
                                   error=error)

        return redirect(url_for('booking_history'))

    return render_template('booking_confirmation.html',
                           showtime_info=showtime,
                           movie_title=movie.get('title') if movie else 'Unknown',
                           theater_name=theater.get('theater_name') if theater else 'Unknown',
                           selected_seats=[],
                           customer_name='')


