DATA_DIR = 'data'

# Helper functions to read and write data files

def load_users():
    users = {}
    path = os.path.join(DATA_DIR, 'users.txt')
    if not os.path.exists(path):
        return users
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            fields = line.strip().split('|')
            if len(fields) == 4:
                username, email, phone, full_name = fields
                users[username] = {
                    'username': username,
                    'email': email,
                    'phone': phone,
                    'full_name': full_name
                }
    return users

def load_menu():
    menu = []
    path = os.path.join(DATA_DIR, 'menu.txt')
    if not os.path.exists(path):
        return menu
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            fields = line.strip().split('|')
            if len(fields) == 8:
                try:
                    dish_id = int(fields[0])
                    price = float(fields[3])
                    avg_rating = float(fields[7])
                    menu.append({
                        'dish_id': dish_id,
                        'name': fields[1],
                        'category': fields[2],
                        'price': price,
                        'description': fields[4],
                        'ingredients': fields[5],
