@app.route('/make-reservation', methods=['POST'])
def submit_reservation():
    guest_name = request.form.get('guest_name', '').strip()
    party_size_str = request.form.get('party_size', '').strip()
    reservation_date = request.form.get('reservation_date', '').strip()

    # Basic validation
    if not guest_name or not party_size_str or not reservation_date:
        # Missing fields: redirect back to make reservation with no messages as per spec
        return redirect(url_for('make_reservation'))

    try:
        party_size = int(party_size_str)
        if party_size < 1 or party_size > 10:
            return redirect(url_for('make_reservation'))
    except ValueError:
        return redirect(url_for('make_reservation'))

    # Validate date format YYYY-MM-DD
    try:
        datetime.strptime(reservation_date, '%Y-%m-%d')
    except ValueError:
        return redirect(url_for('make_reservation'))

    users = load_users()
    user = users.get(CURRENT_USERNAME)
    if user is None:
        return redirect(url_for('dashboard'))

    reservations = load_reservations()
    # New reservation_id
    max_id = max([r['reservation_id'] for r in reservations], default=0)
    new_id = max_id + 1

    # Default time for reservation can be fixed, e.g., 19:00
    new_reservation = {
        'reservation_id': new_id,
        'username': CURRENT_USERNAME,
        'guest_name': guest_name,
        'phone': user['phone'],
        'email': user['email'],
        'party_size': party_size,
        'date': reservation_date,
        'time': '19:00',
        'special_requests': '',
        'status': 'Upcoming'
    }

    reservations.append(new_reservation)
    save_reservations(reservations)

    # Show confirmation page with reservation info
    return render_template('reservation_confirmation.html', reservation=new_reservation)

