@app.route('/waitlist', methods=['GET'])
def waitlist():
    waitlist_data = load_waitlist()
    # Find current user in active waitlist
    user_position = None
    active_waitlist = [w for w in waitlist_data if w['status'] == 'Active']
    active_waitlist_sorted = sorted(active_waitlist, key=lambda x: x['join_time'])
    for idx, entry in enumerate(active_waitlist_sorted, start=1):
        if entry['username'] == CURRENT_USERNAME:
            user_position = idx
            break
    return render_template('waitlist.html', user_position=user_position)

