# Helper functions to load data files

def load_users():
    users = {}
    path = os.path.join(DATA_DIR, 'users.txt')
    if not os.path.exists(path):
        return users
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) >= 4:
                username, email, phone, full_name = parts
                users[username] = {
                    'username': username,
                    'email': email,
                    'phone': phone,
                    'full_name': full_name
                }
    return users


def load_menu():
    menu = []
    path = os.path.join(DATA_DIR, 'menu.txt')
    if not os.path.exists(path):
        return menu
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) >= 8:
                dish_id, name, category, price, description, ingredients, dietary, avg_rating = parts
                try:
                    menu.append({
                        'dish_id': int(dish_id),
                        'name': name,
                        'category': category,
                        'price': float(price),
                        'description': description,
                        'ingredients': ingredients,
                        'dietary': dietary,
                        'avg_rating': float(avg_rating)
                    })
                except ValueError:
                    continue
    return menu


def load_reservations():
    reservations = []
    path = os.path.join(DATA_DIR, 'reservations.txt')
    if not os.path.exists(path):
        return reservations
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) >= 10:
                (reservation_id, username, guest_name, phone, email, party_size, date, time, special_requests, status) = parts
                try:
                    reservations.append({
