from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Load users from users.txt

def load_users():
    users = {}
    path = os.path.join(DATA_DIR, 'users.txt')
    if not os.path.isfile(path):
        return users
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 4:
                username, email, phone, full_name = parts
                users[username] = {
                    'username': username,
                    'email': email,
                    'phone': phone,
                    'full_name': full_name
                }
    return users

# Load menu items from menu.txt

def load_menu():
    menu = []
    path = os.path.join(DATA_DIR, 'menu.txt')
    if not os.path.isfile(path):
        return menu
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 8:
                dish_id, name, category, price, description, ingredients, dietary, avg_rating = parts
                try:
                    menu.append({
                        'dish_id': int(dish_id),
                        'name': name,
                        'category': category,
                        'price': float(price),
                        'description': description,
                        'ingredients': ingredients,
                        'dietary': dietary,
                        'avg_rating': float(avg_rating)
                    })
                except ValueError:
                    continue
    return menu

# Load reservations from reservations.txt

def load_reservations():
    reservations = []
    path = os.path.join(DATA_DIR, 'reservations.txt')
    if not os.path.isfile(path):
        return reservations
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 10:
                (reservation_id, username, guest_name, phone, email, party_size, date, time, special_requests, status) = parts
                try:
                    reservations.append({
                        'reservation_id': int(reservation_id),
                        'username': username,
                        'guest_name': guest_name,
                        'phone': phone,
                        'email': email,
                        'party_size': int(party_size),
                        'date': date,
                        'time': time,
                        'special_requests': special_requests,
                        'status': status
                    })
                except ValueError:
                    continue
    return reservations

# Save reservations to reservations.txt

def save_reservations(reservations):
    path = os.path.join(DATA_DIR, 'reservations.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for r in reservations:
            line = f"{r['reservation_id']}|{r['username']}|{r['guest_name']}|{r['phone']}|{r['email']}|{r['party_size']}|{r['date']}|{r['time']}|{r['special_requests']}|{r['status']}\n"
            f.write(line)

# Load waitlist from waitlist.txt

def load_waitlist():
    waitlist = []
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    if not os.path.isfile(path):
        return waitlist
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 5:
                waitlist_id, username, party_size, join_time, status = parts
                try:
                    waitlist.append({
                        'waitlist_id': int(waitlist_id),
                        'username': username,
                        'party_size': int(party_size),
                        'join_time': join_time,
                        'status': status
                    })
                except ValueError:
                    continue
    return waitlist

# Save waitlist to waitlist.txt

def save_waitlist(waitlist):
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for w in waitlist:
            line = f"{w['waitlist_id']}|{w['username']}|{w['party_size']}|{w['join_time']}|{w['status']}\n"
            f.write(line)

# Load reviews from reviews.txt

def load_reviews():
    reviews = []
    path = os.path.join(DATA_DIR, 'reviews.txt')
    if not os.path.isfile(path):
        return reviews
    with open(path, 'r', encoding='utf-8') as f:
        for line in f:
            parts = line.strip().split('|')
            if len(parts) == 6:
                review_id, username, dish_id, rating, review_text, review_date = parts
                try:
                    reviews.append({
                        'review_id': int(review_id),
                        'username': username,
                        'dish_id': int(dish_id),
                        'rating': int(rating),
                        'review_text': review_text,
                        'review_date': review_date
                    })
                except ValueError:
                    continue
    return reviews

# Save reviews to reviews.txt

def save_reviews(reviews):
    path = os.path.join(DATA_DIR, 'reviews.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for r in reviews:
            line = f"{r['review_id']}|{r['username']}|{r['dish_id']}|{r['rating']}|{r['review_text']}|{r['review_date']}\n"
            f.write(line)

